// ==================== DASHBOARD PAGE ====================

const DashboardPage = () => {
  const [resumes, setResumes] = useState([]);
  const [loading, setLoading] = useState(true);
  const [stats, setStats] = useState({ total: 0, avgScore: 0 });
  const [viewMode, setViewMode] = useState('grid');

  useEffect(() => {
    fetchData();
  }, []);

  const fetchData = async () => {
    try {
      const [resumesRes, historyRes] = await Promise.all([
        api.get('/resume/list'),
        api.get('/analysis/history')
      ]);

      setResumes(resumesRes.data);

      const atsAnalyses = historyRes.data.filter(a => a.analysis_type === 'ats_score');
      const avgScore = atsAnalyses.reduce((sum, a) => sum + (a.ats_score || 0), 0) / (atsAnalyses.length || 1);

      setStats({
        total: resumesRes.data.length,
        avgScore: Math.round(avgScore),
      });
    } catch (error) {
      console.error('Error:', error);
    } finally {
      setLoading(false);
    }
  };

  const statCards = [
    { title: 'Total Resumes', value: stats.total, icon: <DescriptionIcon />, color: '#ff69b4' },
    { title: 'Avg ATS Score', value: `${stats.avgScore}%`, icon: <TrendingUpIcon />, color: '#51cf66' },
  ];

  if (loading) return <Box display="flex" justifyContent="center" alignItems="center" minHeight="60vh"><CircularProgress /></Box>;

  return (
    <Box>
      <Typography variant="h4" gutterBottom fontWeight="bold">Welcome Back! 👋</Typography>
      <Typography variant="body1" color="text.secondary" sx={{ mb: 4 }}>Here's what's happening with your resumes</Typography>

      <Grid container spacing={3} sx={{ mb: 4 }}>
        {statCards.map((stat, index) => (
          <Grid item xs={12} sm={6} key={index}>
            <Card sx={{ p: 3 }}>
              <Box display="flex" justifyContent="space-between" alignItems="center">
                <Box>
                  <Typography color="text.secondary" variant="body2">{stat.title}</Typography>
                  <Typography variant="h3" fontWeight="bold">{stat.value}</Typography>
                </Box>
                <Box sx={{ bgcolor: alpha(stat.color, 0.1), borderRadius: 2, p: 1.5 }}>
                  {React.cloneElement(stat.icon, { sx: { fontSize: 40, color: stat.color } })}
                </Box>
              </Box>
            </Card>
          </Grid>
        ))}
      </Grid>

      <Box sx={{ mb: 4 }}>
        <Box display="flex" justifyContent="space-between" alignItems="center" sx={{ mb: 3 }}>
          <Typography variant="h5" fontWeight="bold">My Resumes</Typography>
          <Box display="flex" gap={1}>
            <ToggleButtonGroup value={viewMode} exclusive onChange={(e, v) => v && setViewMode(v)} size="small">
              <ToggleButton value="grid"><AppsIcon /></ToggleButton>
              <ToggleButton value="list"><FormatListBulletedIcon /></ToggleButton>
            </ToggleButtonGroup>
            <Button variant="contained" startIcon={<AddIcon />} component={Link} to="/upload">Upload</Button>
          </Box>
        </Box>

        {resumes.length === 0 ? (
          <Card sx={{ textAlign: 'center', py: 8 }}>
            <InsertDriveFileIcon sx={{ fontSize: 80, color: 'text.secondary', mb: 2 }} />
            <Typography variant="h6" gutterBottom>No Resumes Yet</Typography>
            <Button variant="contained" component={Link} to="/upload" startIcon={<CloudUploadIcon />} sx={{ mt: 2 }}>Upload Resume</Button>
          </Card>
        ) : viewMode === 'grid' ? (
          <Grid container spacing={3}>
            {resumes.map((resume) => (
              <Grid item xs={12} sm={6} md={4} key={resume.id}>
                <Card>
                  <CardContent>
                    <Box display="flex" alignItems="center" gap={2} sx={{ mb: 2 }}>
                      <Avatar sx={{ bgcolor: '#ff69b4', width: 48, height: 48 }}>
                        {resume.name?.[0] || <DescriptionIcon />}
                      </Avatar>
                      <Box flex={1}>
                        <Typography variant="h6" noWrap>{resume.name || 'Unnamed Resume'}</Typography>
                        <Typography variant="body2" color="text.secondary" noWrap>{resume.filename}</Typography>
                      </Box>
                    </Box>
                    <Box sx={{ mb: 2 }}>
                      <Typography variant="body2" color="text.secondary" gutterBottom>Skills</Typography>
                      <Box display="flex" flexWrap="wrap" gap={0.5}>
                        {resume.skills?.slice(0, 4).map(skill => (
                          <Chip key={skill} label={skill} size="small" variant="outlined" />
                        ))}
                      </Box>
                    </Box>
                  </CardContent>
                  <Divider />
                  <CardActions sx={{ p: 2, gap: 1 }}>
                    <Button size="small" startIcon={<AssessmentIcon />} component={Link} to={`/analyze?resume=${resume.id}`}>Analyze</Button>
                    <Button size="small" startIcon={<WorkIcon />} component={Link} to={`/match?resume=${resume.id}`}>Match Jobs</Button>
                  </CardActions>
                </Card>
              </Grid>
            ))}
          </Grid>
        ) : (
          <TableContainer component={Paper}>
            <Table>
              <TableHead>
                <TableRow>
                  <TableCell>Name</TableCell>
                  <TableCell>Filename</TableCell>
                  <TableCell>Skills</TableCell>
                  <TableCell>Actions</TableCell>
                </TableRow>
              </TableHead>
              <TableBody>
                {resumes.map((resume) => (
                  <TableRow key={resume.id}>
                    <TableCell>{resume.name || 'Unnamed'}</TableCell>
                    <TableCell>{resume.filename}</TableCell>
                    <TableCell>
                      <Box display="flex" gap={0.5} flexWrap="wrap">
                        {resume.skills?.slice(0, 3).map(skill => <Chip key={skill} label={skill} size="small" />)}
                      </Box>
                    </TableCell>
                    <TableCell>
                      <IconButton size="small" component={Link} to={`/analyze?resume=${resume.id}`}><AssessmentIcon /></IconButton>
                      <IconButton size="small" component={Link} to={`/match?resume=${resume.id}`}><WorkIcon /></IconButton>
                    </TableCell>
                  </TableRow>
                ))}
              </TableBody>
            </Table>
          </TableContainer>
        )}
      </Box>
    </Box>
  );
};

// ==================== UPLOAD PAGE ====================

const UploadPage = () => {
  const [file, setFile] = useState(null);
  const [uploading, setUploading] = useState(false);
  const [message, setMessage] = useState({ type: '', text: '' });
  const navigate = useNavigate();

  const handleUpload = async () => {
    if (!file) {
      setMessage({ type: 'error', text: 'Please select a file' });
      return;
    }

    const formData = new FormData();
    formData.append('file', file);
    setUploading(true);
    try {
      await api.post('/resume/upload', formData, { headers: { 'Content-Type': 'multipart/form-data' } });
      setMessage({ type: 'success', text: 'Resume uploaded successfully! Redirecting...' });
      setTimeout(() => navigate('/dashboard'), 2000);
    } catch (error) {
      setMessage({ type: 'error', text: error.response?.data?.detail || 'Upload failed' });
    } finally {
      setUploading(false);
    }
  };

  return (
    <Box>
      <Typography variant="h4" gutterBottom fontWeight="bold">Upload Resume</Typography>
      <Typography variant="body1" color="text.secondary" sx={{ mb: 4 }}>Upload your resume in PDF or DOCX format</Typography>

      <Grid container spacing={4}>
        <Grid item xs={12} md={7}>
          <Card sx={{ p: 3 }}>
            <DropzoneArea
              acceptedFiles={['application/pdf', 'application/vnd.openxmlformats-officedocument.wordprocessingml.document']}
              maxFileSize={10 * 1024 * 1024}
              filesLimit={1}
              onChange={(files) => setFile(files[0])}
              showAlerts={false}
              dropzoneText="Drag and drop your resume here or click to browse"
            />
            <Box sx={{ mt: 3, display: 'flex', justifyContent: 'center' }}>
              <Button variant="contained" onClick={handleUpload} disabled={!file || uploading} startIcon={<CloudUploadIcon />} size="large">
                {uploading ? <CircularProgress size={24} /> : 'Upload Resume'}
              </Button>
            </Box>
            {message.text && (
              <Alert severity={message.type} sx={{ mt: 2 }}>
                {message.text}
              </Alert>
            )}
          </Card>
        </Grid>

        <Grid item xs={12} md={5}>
          <Card sx={{ p: 3, bgcolor: '#fff0f5' }}>
            <Typography variant="h6" gutterBottom>Supported Formats</Typography>
            <Box display="flex" gap={2} sx={{ mb: 3 }}>
              <Chip icon={<PictureAsPdfIcon />} label="PDF" color="primary" variant="outlined" />
              <Chip icon={<ArticleIcon />} label="DOCX" color="primary" variant="outlined" />
            </Box>
            <Typography variant="body2" color="text.secondary" gutterBottom>Requirements:</Typography>
            <List dense>
              <ListItem><CheckIcon sx={{ mr: 1, color: 'success.main', fontSize: 16 }} />Maximum file size: 10MB</ListItem>
              <ListItem><CheckIcon sx={{ mr: 1, color: 'success.main', fontSize: 16 }} />Text-based PDF or Word documents</ListItem>
              <ListItem><CheckIcon sx={{ mr: 1, color: 'success.main', fontSize: 16 }} />Clear section headings</ListItem>
            </List>
          </Card>
        </Grid>
      </Grid>
    </Box>
  );
};

// ==================== ATS ANALYSIS PAGE WITH FEEDBACK ====================

const ATSAnalysisPage = () => {
  const [resumes, setResumes] = useState([]);
  const [selectedResume, setSelectedResume] = useState(null);
  const [analysis, setAnalysis] = useState(null);
  const [analyzing, setAnalyzing] = useState(false);
  const [tabValue, setTabValue] = useState(0);
  const location = useLocation();

  useEffect(() => {
    fetchResumes();
    // Check for resume ID in URL query params
    const params = new URLSearchParams(location.search);
    const resumeId = params.get('resume');
    if (resumeId) {
      setSelectedResume(parseInt(resumeId));
    }
  }, [location]);

  const fetchResumes = async () => {
    try {
      const response = await api.get('/resume/list');
      setResumes(response.data);
    } catch (error) {
      console.error('Error:', error);
    }
  };

  const handleAnalyze = async () => {
    if (!selectedResume) return;
    setAnalyzing(true);
    try {
      const response = await api.post('/analyze/ats', { resume_id: selectedResume });
      setAnalysis(response.data);
    } catch (error) {
      console.error('Analysis error:', error);
    } finally {
      setAnalyzing(false);
    }
  };

  const getScoreColor = (score) => {
    if (score >= 80) return '#51cf66';
    if (score >= 60) return '#ff922b';
    return '#ff6b6b';
  };

  const getScoreLabel = (score) => {
    if (score >= 80) return 'Excellent! Your resume is well-optimized';
    if (score >= 60) return 'Good! Room for improvement';
    if (score >= 40) return 'Needs Work! Several areas to improve';
    return 'Requires Significant Improvement';
  };

  return (
    <Box>
      <Typography variant="h4" gutterBottom fontWeight="bold">ATS Analysis</Typography>
      <Typography variant="body1" color="text.secondary" sx={{ mb: 4 }}>Get AI-powered ATS score and detailed feedback analysis</Typography>

      <Grid container spacing={4}>
        <Grid item xs={12} md={4}>
          <Card>
            <CardContent>
              <Typography variant="h6" gutterBottom>Select Resume</Typography>
              <FormControl fullWidth sx={{ mb: 2 }}>
                <InputLabel>Choose a resume</InputLabel>
                <Select
                  value={selectedResume || ''}
                  onChange={(e) => setSelectedResume(e.target.value)}
                  label="Choose a resume"
                  startAdornment={<DescriptionIcon sx={{ mr: 1, color: '#ff69b4' }} />}
                >
                  {resumes.map((resume) => (
                    <MenuItem key={resume.id} value={resume.id}>
                      <Box display="flex" alignItems="center" gap={1}>
                        <DescriptionIcon fontSize="small" />
                        <span>{resume.name || resume.filename}</span>
                      </Box>
                    </MenuItem>
                  ))}
                </Select>
                {resumes.length === 0 && (
                  <FormHelperText>No resumes uploaded. Please upload a resume first.</FormHelperText>
                )}
              </FormControl>
              <Button
                variant="contained"
                fullWidth
                onClick={handleAnalyze}
                disabled={!selectedResume || analyzing}
                sx={{ mt: 2 }}
                startIcon={<AutoAwesomeIcon />}
              >
                {analyzing ? <CircularProgress size={24} /> : 'Analyze with AI'}
              </Button>
            </CardContent>
          </Card>
        </Grid>

        <Grid item xs={12} md={8}>
          {analysis ? (
            <Fade in>
              <Box>
                {/* Score Card */}
                <Card sx={{ mb: 3 }}>
                  <CardContent>
                    <Box textAlign="center">
                      <Box sx={{ position: 'relative', display: 'inline-block', mb: 2 }}>
                        <CircularProgress
                          variant="determinate"
                          value={analysis.ats_score}
                          size={140}
                          thickness={4}
                          sx={{ color: getScoreColor(analysis.ats_score) }}
                        />
                        <Box sx={{ position: 'absolute', top: '50%', left: '50%', transform: 'translate(-50%, -50%)' }}>
                          <Typography variant="h2" fontWeight="bold">{Math.round(analysis.ats_score)}%</Typography>
                        </Box>
                      </Box>
                      <Typography variant="h6" sx={{ color: getScoreColor(analysis.ats_score), mb: 1 }}>
                        {getScoreLabel(analysis.ats_score)}
                      </Typography>

                      {/* Score Breakdown */}
                      {analysis.score_breakdown && (
                        <Grid container spacing={2} sx={{ mt: 2 }}>
                          <Grid item xs={6} sm={3}>
                            <Box textAlign="center">
                              <Typography variant="body2" color="text.secondary">Keywords</Typography>
                              <Typography variant="h6">{Math.round(analysis.score_breakdown.keyword_optimization)}%</Typography>
                              <LinearProgress variant="determinate" value={analysis.score_breakdown.keyword_optimization} sx={{ height: 4, borderRadius: 2 }} />
                            </Box>
                          </Grid>
                          <Grid item xs={6} sm={3}>
                            <Box textAlign="center">
                              <Typography variant="body2" color="text.secondary">Formatting</Typography>
                              <Typography variant="h6">{Math.round(analysis.score_breakdown.formatting)}%</Typography>
                              <LinearProgress variant="determinate" value={analysis.score_breakdown.formatting} sx={{ height: 4, borderRadius: 2 }} />
                            </Box>
                          </Grid>
                          <Grid item xs={6} sm={3}>
                            <Box textAlign="center">
                              <Typography variant="body2" color="text.secondary">Content</Typography>
                              <Typography variant="h6">{Math.round(analysis.score_breakdown.content_relevance)}%</Typography>
                              <LinearProgress variant="determinate" value={analysis.score_breakdown.content_relevance} sx={{ height: 4, borderRadius: 2 }} />
                            </Box>
                          </Grid>
                          <Grid item xs={6} sm={3}>
                            <Box textAlign="center">
                              <Typography variant="body2" color="text.secondary">Achievements</Typography>
                              <Typography variant="h6">{Math.round(analysis.score_breakdown.quantifiable_achievements)}%</Typography>
                              <LinearProgress variant="determinate" value={analysis.score_breakdown.quantifiable_achievements} sx={{ height: 4, borderRadius: 2 }} />
                            </Box>
                          </Grid>
                        </Grid>
                      )}
                    </Box>
                  </CardContent>
                </Card>

                {/* Tabs for detailed analysis */}
                <Card>
                  <CardContent>
                    <Tabs value={tabValue} onChange={(e, v) => setTabValue(v)} sx={{ mb: 3 }} variant="scrollable" scrollButtons="auto">
                      <Tab icon={<ThumbUpIcon />} label="Strengths" />
                      <Tab icon={<ThumbDownIcon />} label="Weaknesses" />
                      <Tab icon={<SearchIcon />} label="Missing Keywords" />
                      <Tab icon={<AutoAwesomeIcon />} label="Suggestions" />
                      <Tab icon={<PsychologyIcon />} label="Gap Analysis" />
                      <Tab icon={<TimelineIcon />} label="Improvement Plan" />
                    </Tabs>

                    <Box sx={{ mt: 2 }}>
                      {tabValue === 0 && (
                        <List>
                          {analysis.strengths?.map((strength, i) => (
                            <ListItem key={i}>
                              <CheckCircleIcon sx={{ color: 'success.main', mr: 2 }} />
                              <Typography>{strength}</Typography>
                            </ListItem>
                          ))}
                        </List>
                      )}

                      {tabValue === 1 && (
                        <List>
                          {analysis.weaknesses?.map((weakness, i) => (
                            <ListItem key={i}>
                              <ErrorIcon sx={{ color: 'error.main', mr: 2 }} />
                              <Typography>{weakness}</Typography>
                            </ListItem>
                          ))}
                        </List>
                      )}

                      {tabValue === 2 && (
                        <Box>
                          <Alert severity="warning" sx={{ mb: 2 }}>
                            Add these keywords to improve your ATS score
                          </Alert>
                          <Box sx={{ display: 'flex', flexWrap: 'wrap', gap: 1 }}>
                            {analysis.missing_keywords?.map((keyword, i) => (
                              <Chip key={i} label={keyword} color="warning" icon={<WarningIcon />} />
                            ))}
                          </Box>
                        </Box>
                      )}

                      {tabValue === 3 && (
                        <List>
                          {analysis.suggestions?.map((suggestion, i) => (
                            <ListItem key={i}>
                              <LightbulbIcon sx={{ color: 'warning.main', mr: 2 }} />
                              <Typography>{suggestion}</Typography>
                            </ListItem>
                          ))}
                        </List>
                      )}

                      {tabValue === 4 && analysis.gap_analysis && (
                        <Box>
                          <Accordion defaultExpanded>
                            <AccordionSummary expandIcon={<ExpandMoreIcon />}>
                              <Typography variant="h6"><SchoolIcon sx={{ mr: 1, verticalAlign: 'middle' }} /> Skill Gaps</Typography>
                            </AccordionSummary>
                            <AccordionDetails>
                              <List>
                                {analysis.gap_analysis.skill_gaps?.map((gap, i) => (
                                  <ListItem key={i}>
                                    <TrendingDownIcon sx={{ color: 'error.main', mr: 2 }} />
                                    <Typography>{gap}</Typography>
                                  </ListItem>
                                ))}
                              </List>
                            </AccordionDetails>
                          </Accordion>

                          <Accordion>
                            <AccordionSummary expandIcon={<ExpandMoreIcon />}>
                              <Typography variant="h6"><WorkHistoryIcon sx={{ mr: 1, verticalAlign: 'middle' }} /> Experience Gaps</Typography>
                            </AccordionSummary>
                            <AccordionDetails>
                              <List>
                                {analysis.gap_analysis.experience_gaps?.map((gap, i) => (
                                  <ListItem key={i}>
                                    <ErrorIcon sx={{ color: 'warning.main', mr: 2 }} />
                                    <Typography>{gap}</Typography>
                                  </ListItem>
                                ))}
                              </List>
                            </AccordionDetails>
                          </Accordion>

                          <Accordion>
                            <AccordionSummary expandIcon={<ExpandMoreIcon />}>
                              <Typography variant="h6"><SchoolIcon sx={{ mr: 1, verticalAlign: 'middle' }} /> Education Gaps</Typography>
                            </AccordionSummary>
                            <AccordionDetails>
                              <List>
                                {analysis.gap_analysis.education_gaps?.map((gap, i) => (
                                  <ListItem key={i}>
                                    <SchoolIcon sx={{ color: 'info.main', mr: 2 }} />
                                    <Typography>{gap}</Typography>
                                  </ListItem>
                                ))}
                              </List>
                            </AccordionDetails>
                          </Accordion>
                        </Box>
                      )}

                      {tabValue === 5 && analysis.improvement_plan && (
                        <Box>
                          <Typography variant="h6" gutterBottom>📋 Your Personalized Improvement Plan</Typography>

                          <Stepper orientation="vertical">
                            <Step active>
                              <StepLabel>Short-term (1-2 weeks)</StepLabel>
                              <StepContent>
                                <List>
                                  {analysis.improvement_plan.short_term?.map((item, i) => (
                                    <ListItem key={i}>
                                      <CheckIcon sx={{ color: 'success.main', mr: 1 }} />
                                      <Typography>{item}</Typography>
                                    </ListItem>
                                  ))}
                                </List>
                              </StepContent>
                            </Step>

                            <Step active>
                              <StepLabel>Medium-term (1-3 months)</StepLabel>
                              <StepContent>
                                <List>
                                  {analysis.improvement_plan.medium_term?.map((item, i) => (
                                    <ListItem key={i}>
                                      <TrendingUpIcon sx={{ color: 'warning.main', mr: 1 }} />
                                      <Typography>{item}</Typography>
                                    </ListItem>
                                  ))}
                                </List>
                              </StepContent>
                            </Step>

                            <Step active>
                              <StepLabel>Long-term (3-6 months)</StepLabel>
                              <StepContent>
                                <List>
                                  {analysis.improvement_plan.long_term?.map((item, i) => (
                                    <ListItem key={i}>
                                      <CelebrationIcon sx={{ color: 'primary.main', mr: 1 }} />
                                      <Typography>{item}</Typography>
                                    </ListItem>
                                  ))}
                                </List>
                              </StepContent>
                            </Step>
                          </Stepper>
                        </Box>
                      )}
                    </Box>

                    {analysis.detailed_feedback && (
                      <Alert severity="info" sx={{ mt: 3 }}>
                        <AlertTitle>Overall Assessment</AlertTitle>
                        {analysis.detailed_feedback}
                      </Alert>
                    )}
                  </CardContent>
                </Card>
              </Box>
            </Fade>
          ) : (
            <Card sx={{ textAlign: 'center', py: 8 }}>
              <PsychologyIcon sx={{ fontSize: 80, color: 'text.secondary', mb: 2 }} />
              <Typography variant="h6" gutterBottom>No Analysis Yet</Typography>
              <Typography color="text.secondary">Select a resume from the dropdown and click "Analyze with AI"</Typography>
            </Card>
          )}
        </Grid>
      </Grid>
    </Box>
  );
};

// ==================== JOB MATCHER PAGE ====================

const JobMatcherPage = () => {
  const [resumes, setResumes] = useState([]);
  const [selectedResume, setSelectedResume] = useState(null);
  const [jobDescription, setJobDescription] = useState('');
  const [match, setMatch] = useState(null);
  const [matching, setMatching] = useState(false);
  const [openDialog, setOpenDialog] = useState(false);
  const location = useLocation();

  useEffect(() => {
    fetchResumes();
    const params = new URLSearchParams(location.search);
    const resumeId = params.get('resume');
    if (resumeId) {
      setSelectedResume(parseInt(resumeId));
    }
  }, [location]);

  const fetchResumes = async () => {
    try {
      const response = await api.get('/resume/list');
      setResumes(response.data);
    } catch (error) {
      console.error('Error:', error);
    }
  };

  const handleMatch = async () => {
    if (!selectedResume || !jobDescription) return;
    setMatching(true);
    try {
      const response = await api.post('/analyze/match-job', { resume_id: selectedResume, job_description: jobDescription });
      setMatch(response.data);
      setOpenDialog(true);
    } catch (error) {
      console.error('Matching error:', error);
    } finally {
      setMatching(false);
    }
  };

  return (
    <Box>
      <Typography variant="h4" gutterBottom fontWeight="bold">Job Matcher</Typography>
      <Typography variant="body1" color="text.secondary" sx={{ mb: 4 }}>Match your resume with job descriptions to find the perfect fit</Typography>

      <Grid container spacing={4}>
        <Grid item xs={12} md={4}>
          <Card>
            <CardContent>
              <Typography variant="h6" gutterBottom>Select Resume</Typography>
              <FormControl fullWidth sx={{ mb: 2 }}>
                <InputLabel>Choose a resume</InputLabel>
                <Select
                  value={selectedResume || ''}
                  onChange={(e) => setSelectedResume(e.target.value)}
                  label="Choose a resume"
                  startAdornment={<DescriptionIcon sx={{ mr: 1, color: '#ff69b4' }} />}
                >
                  {resumes.map((resume) => (
                    <MenuItem key={resume.id} value={resume.id}>
                      <Box display="flex" alignItems="center" gap={1}>
                        <DescriptionIcon fontSize="small" />
                        <span>{resume.name || resume.filename}</span>
                        <Chip label={`${resume.skills?.length || 0} skills`} size="small" sx={{ ml: 1 }} />
                      </Box>
                    </MenuItem>
                  ))}
                </Select>
                {resumes.length === 0 && (
                  <FormHelperText>No resumes uploaded. Please upload a resume first.</FormHelperText>
                )}
              </FormControl>
            </CardContent>
          </Card>
        </Grid>

        <Grid item xs={12} md={8}>
          <Card>
            <CardContent>
              <Typography variant="h6" gutterBottom>Job Description</Typography>
              <TextField
                fullWidth
                multiline
                rows={8}
                placeholder="Paste the job description here..."
                value={jobDescription}
                onChange={(e) => setJobDescription(e.target.value)}
                sx={{ mb: 2 }}
              />
              <Button
                variant="contained"
                fullWidth
                onClick={handleMatch}
                disabled={!selectedResume || !jobDescription || matching}
                size="large"
                startIcon={<WorkIcon />}
              >
                {matching ? <CircularProgress size={24} /> : 'Match with Job'}
              </Button>
            </CardContent>
          </Card>
        </Grid>
      </Grid>

      <Dialog open={openDialog} onClose={() => setOpenDialog(false)} maxWidth="md" fullWidth>
        <DialogTitle>
          <Box display="flex" justifyContent="space-between" alignItems="center">
            <Typography variant="h5">Match Results</Typography>
            <Box textAlign="center">
              <Typography variant="h2" color="primary" fontWeight="bold">{Math.round(match?.match_percentage || 0)}%</Typography>
              <Typography variant="body2">Match Score</Typography>
              <LinearProgress variant="determinate" value={match?.match_percentage || 0} sx={{ mt: 1, width: 100 }} />
            </Box>
          </Box>
        </DialogTitle>
        <DialogContent dividers>
          <Typography variant="h6" gutterBottom>Role Fit Summary</Typography>
          <Typography paragraph sx={{ bgcolor: '#fff0f5', p: 2, borderRadius: 2 }}>
            {match?.role_fit_summary}
          </Typography>

          <Typography variant="h6" gutterBottom>✅ Matched Skills</Typography>
          <Box sx={{ display: 'flex', flexWrap: 'wrap', gap: 1, mb: 3 }}>
            {match?.matched_skills?.map((skill, i) => (
              <Chip key={i} label={skill} color="success" icon={<CheckCircleIcon />} />
            ))}
          </Box>

          <Typography variant="h6" gutterBottom>❌ Missing Skills</Typography>
          <Box sx={{ display: 'flex', flexWrap: 'wrap', gap: 1, mb: 3 }}>
            {match?.missing_skills?.map((skill, i) => (
              <Chip key={i} label={skill} color="error" icon={<ErrorIcon />} />
            ))}
          </Box>

          {match?.gap_analysis && (
            <>
              <Typography variant="h6" gutterBottom>📊 Gap Analysis</Typography>
              <Accordion>
                <AccordionSummary expandIcon={<ExpandMoreIcon />}>
                  <Typography>Skill Gaps</Typography>
                </AccordionSummary>
                <AccordionDetails>
                  <List>
                    {match.gap_analysis.skill_gaps?.map((gap, i) => (
                      <ListItem key={i}><LightbulbIcon sx={{ mr: 1, color: 'warning.main' }} />{gap}</ListItem>
                    ))}
                  </List>
                </AccordionDetails>
              </Accordion>
            </>
          )}

          {match?.improvement_tips && (
            <>
              <Typography variant="h6" gutterBottom>💡 Improvement Tips</Typography>
              <List>
                {match.improvement_tips?.map((tip, i) => (
                  <ListItem key={i}>
                    <AutoAwesomeIcon sx={{ mr: 1, color: 'primary.main' }} />
                    <Typography>{tip}</Typography>
                  </ListItem>
                ))}
              </List>
            </>
          )}
        </DialogContent>
        <DialogActions>
          <Button onClick={() => setOpenDialog(false)}>Close</Button>
        </DialogActions>
      </Dialog>
    </Box>
  );
};

// ==================== HISTORY PAGE ====================

const HistoryPage = () => {
  const [history, setHistory] = useState([]);
  const [loading, setLoading] = useState(true);
  const [filter, setFilter] = useState('all');

  useEffect(() => {
    fetchHistory();
  }, []);

  const fetchHistory = async () => {
    try {
      const response = await api.get('/analysis/history');
      setHistory(response.data);
    } catch (error) {
      console.error('Error:', error);
    } finally {
      setLoading(false);
    }
  };

  const filteredHistory = history.filter(item => filter === 'all' || item.analysis_type === filter);

  if (loading) return <Box display="flex" justifyContent="center" alignItems="center" minHeight="60vh"><CircularProgress /></Box>;

  return (
    <Box>
      <Typography variant="h4" gutterBottom fontWeight="bold">Analysis History</Typography>
      <Typography variant="body1" color="text.secondary" sx={{ mb: 4 }}>View all your past resume analyses</Typography>

      <Box sx={{ mb: 3, display: 'flex', gap: 2 }}>
        <ToggleButtonGroup value={filter} exclusive onChange={(e, v) => v && setFilter(v)}>
          <ToggleButton value="all">All</ToggleButton>
          <ToggleButton value="ats_score">ATS Scores</ToggleButton>
          <ToggleButton value="job_match">Job Matches</ToggleButton>
        </ToggleButtonGroup>
      </Box>

      <Grid container spacing={2}>
        {filteredHistory.map((item) => (
          <Grid item xs={12} key={item.id}>
            <Grow in>
              <Card>
                <CardContent>
                  <Box display="flex" justifyContent="space-between" alignItems="center" flexWrap="wrap">
                    <Box>
                      <Typography variant="h6">{item.resume_name}</Typography>
                      <Typography variant="body2" color="text.secondary">
                        {new Date(item.created_at).toLocaleString()}
                      </Typography>
                      <Chip
                        label={item.analysis_type === 'ats_score' ? 'ATS Score' : 'Job Match'}
                        size="small"
                        sx={{ mt: 1, bgcolor: item.analysis_type === 'ats_score' ? '#ff69b4' : '#ff6b6b', color: 'white' }}
                      />
                    </Box>
                    <Box textAlign="center">
                      <Typography variant="h3" color={item.analysis_type === 'ats_score' ? 'primary' : 'secondary'} fontWeight="bold">
                        {Math.round(item.analysis_type === 'ats_score' ? item.ats_score : item.match_percentage || 0)}%
                      </Typography>
                      <Typography variant="caption">{item.analysis_type === 'ats_score' ? 'ATS Score' : 'Match Rate'}</Typography>
                    </Box>
                  </Box>
                </CardContent>
              </Card>
            </Grow>
          </Grid>
        ))}
      </Grid>

      {history.length === 0 && (
        <Paper sx={{ textAlign: 'center', py: 8 }}>
          <HistoryIcon sx={{ fontSize: 80, color: 'text.secondary', mb: 2 }} />
          <Typography variant="h6">No History Yet</Typography>
          <Button variant="contained" component={Link} to="/upload" sx={{ mt: 2 }}>Upload Resume</Button>
        </Paper>
      )}
    </Box>
  );
};

// ==================== LOGIN PAGE ====================

const LoginPage = () => {
  const [username, setUsername] = useState('');
  const [password, setPassword] = useState('');
  const [error, setError] = useState('');
  const [loading, setLoading] = useState(false);
  const { login } = React.useContext(AuthContext);
  const navigate = useNavigate();

  const handleSubmit = async (e) => {
    e.preventDefault();
    setLoading(true);
    setError('');
    try {
      await login(username, password);
      navigate('/dashboard');
    } catch (error) {
      setError('Invalid username or password');
    } finally {
      setLoading(false);
    }
  };

  return (
    <Box sx={{ minHeight: '100vh', display: 'flex', alignItems: 'center', justifyContent: 'center', background: 'linear-gradient(135deg, #ff69b4 0%, #ff1493 100%)' }}>
      <Container maxWidth="sm">
        <Card sx={{ p: 4 }}>
          <Box textAlign="center" mb={4}>
            <Avatar sx={{ bgcolor: '#ff69b4', width: 64, height: 64, margin: '0 auto', mb: 2 }}><AnalyticsIcon sx={{ fontSize: 32 }} /></Avatar>
            <Typography variant="h4" fontWeight="bold">Welcome Back</Typography>
          </Box>
          <form onSubmit={handleSubmit}>
            <TextField fullWidth label="Username" value={username} onChange={(e) => setUsername(e.target.value)} margin="normal" required />
            <TextField fullWidth label="Password" type="password" value={password} onChange={(e) => setPassword(e.target.value)} margin="normal" required />
            {error && <Alert severity="error" sx={{ mt: 2 }}>{error}</Alert>}
            <Button type="submit" fullWidth variant="contained" size="large" disabled={loading} sx={{ mt: 3 }}>
              {loading ? <CircularProgress size={24} /> : 'Sign In'}
            </Button>
          </form>
          <Box textAlign="center" mt={2}>
            <Typography variant="body2">Don't have an account? <Link to="/signup" style={{ color: '#ff69b4' }}>Sign Up</Link></Typography>
          </Box>
        </Card>
      </Container>
    </Box>
  );
};

// ==================== SIGNUP PAGE ====================

const SignupPage = () => {
  const [formData, setFormData] = useState({ username: '', email: '', password: '' });
  const [error, setError] = useState('');
  const [success, setSuccess] = useState(false);
  const [loading, setLoading] = useState(false);
  const { signup } = React.useContext(AuthContext);
  const navigate = useNavigate();

  const handleSubmit = async (e) => {
    e.preventDefault();
    setLoading(true);
    setError('');
    try {
      await signup(formData);
      setSuccess(true);
      setTimeout(() => navigate('/login'), 2000);
    } catch (error) {
      setError(error.response?.data?.detail || 'Signup failed');
    } finally {
      setLoading(false);
    }
  };

  return (
    <Box sx={{ minHeight: '100vh', display: 'flex', alignItems: 'center', justifyContent: 'center', background: 'linear-gradient(135deg, #ff69b4 0%, #ff1493 100%)' }}>
      <Container maxWidth="sm">
        <Card sx={{ p: 4 }}>
          <Box textAlign="center" mb={4}>
            <Avatar sx={{ bgcolor: '#ff69b4', width: 64, height: 64, margin: '0 auto', mb: 2 }}><AppRegistrationIcon sx={{ fontSize: 32 }} /></Avatar>
            <Typography variant="h4" fontWeight="bold">Create Account</Typography>
          </Box>
          <form onSubmit={handleSubmit}>
            <TextField fullWidth label="Username" value={formData.username} onChange={(e) => setFormData({ ...formData, username: e.target.value })} margin="normal" required />
            <TextField fullWidth label="Email" type="email" value={formData.email} onChange={(e) => setFormData({ ...formData, email: e.target.value })} margin="normal" required />
            <TextField fullWidth label="Password" type="password" value={formData.password} onChange={(e) => setFormData({ ...formData, password: e.target.value })} margin="normal" required />
            {error && <Alert severity="error" sx={{ mt: 2 }}>{error}</Alert>}
            {success && <Alert severity="success" sx={{ mt: 2 }}>Account created! Redirecting to login...</Alert>}
            <Button type="submit" fullWidth variant="contained" size="large" disabled={loading} sx={{ mt: 3 }}>
              {loading ? <CircularProgress size={24} /> : 'Sign Up'}
            </Button>
          </form>
          <Box textAlign="center" mt={2}>
            <Typography variant="body2">Already have an account? <Link to="/login" style={{ color: '#ff69b4' }}>Sign In</Link></Typography>
          </Box>
        </Card>
      </Container>
    </Box>
  );
};

// ==================== MAIN APP ====================

const App = () => {
  const { user, loading } = React.useContext(AuthContext);
  if (loading) return <Box display="flex" justifyContent="center" alignItems="center" minHeight="100vh"><CircularProgress /></Box>;

  return (
    <Router>
      <Routes>
        <Route path="/" element={<HomePage />} />
        <Route path="/login" element={user ? <Navigate to="/dashboard" /> : <LoginPage />} />
        <Route path="/signup" element={user ? <Navigate to="/dashboard" /> : <SignupPage />} />
        <Route path="/dashboard" element={user ? <Layout><DashboardPage /></Layout> : <Navigate to="/login" />} />
        <Route path="/upload" element={user ? <Layout><UploadPage /></Layout> : <Navigate to="/login" />} />
        <Route path="/analyze" element={user ? <Layout><ATSAnalysisPage /></Layout> : <Navigate to="/login" />} />
        <Route path="/match" element={user ? <Layout><JobMatcherPage /></Layout> : <Navigate to="/login" />} />
        <Route path="/history" element={user ? <Layout><HistoryPage /></Layout> : <Navigate to="/login" />} />
      </Routes>
    </Router>
  );
};

// ==================== APP WRAPPER ====================

const AppWrapper = () => {
  return (
    <ThemeProvider theme={theme}>
      <CssBaseline />
      <AuthProvider>
        <App />
      </AuthProvider>
    </ThemeProvider>
  );
};

export default AppWrapper;
